// Build status response
const row = $input.first().json;

const totalLines = parseInt(row.total_lines || 0);
const numEntries = parseInt(row.number_of_entries || 0);
const numOutputs = parseInt(row.number_of_outputs || 0);

// Se entries e outputs processados = total, então não está rodando
const running = !(numEntries === totalLines && numOutputs === totalLines);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_status',
  event: 'status_checked',
  running: running,
  total_lines: totalLines,
  entries: numEntries,
  outputs: numOutputs,
  level: 'info'
}));

return {
  running: running,
  total_lines: totalLines,
  number_of_entries: numEntries,
  number_of_outputs: numOutputs
};
